/**
 * Splits text into highlighted and non-highlighted segments using accent-insensitive matching.
 * @param {string} text
 * @param {string} searchQuery
 * @returns {Array<{ text: string, highlighted: boolean }>}
 */
function splitHighlightedText(text, searchQuery) {
  const source = String(text ?? '');
  const query = String(searchQuery ?? '').trim();
  if (!source || !query) {
    return [{ text: source, highlighted: false }];
  }

  const normalizedChars = [];
  const originalIndexes = [];

  for (let i = 0; i < source.length; i += 1) {
    const folded = source[i].toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
    for (let j = 0; j < folded.length; j += 1) {
      normalizedChars.push(folded[j]);
      originalIndexes.push(i);
    }
  }

  const normalizedText = normalizedChars.join('');
  const normalizedQuery = query.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  if (!normalizedQuery || !normalizedText.includes(normalizedQuery)) {
    return [{ text: source, highlighted: false }];
  }

  const matchRanges = [];
  let fromIndex = 0;
  while (fromIndex < normalizedText.length) {
    const matchStart = normalizedText.indexOf(normalizedQuery, fromIndex);
    if (matchStart === -1) {
      break;
    }
    const matchEnd = matchStart + normalizedQuery.length - 1;
    matchRanges.push({
      start: originalIndexes[matchStart],
      end: originalIndexes[matchEnd] + 1,
    });
    fromIndex = matchStart + normalizedQuery.length;
  }

  const mergedRanges = [];
  for (const range of matchRanges) {
    const lastRange = mergedRanges[mergedRanges.length - 1];
    if (!lastRange || range.start > lastRange.end) {
      mergedRanges.push({ ...range });
    } else {
      lastRange.end = Math.max(lastRange.end, range.end);
    }
  }

  const segments = [];
  let cursor = 0;
  for (const range of mergedRanges) {
    if (range.start > cursor) {
      segments.push({ text: source.slice(cursor, range.start), highlighted: false });
    }
    segments.push({ text: source.slice(range.start, range.end), highlighted: true });
    cursor = range.end;
  }

  if (cursor < source.length) {
    segments.push({ text: source.slice(cursor), highlighted: false });
  }

  return segments;
}

